message.content:
@startuml
skinparam shadowing false
skinparam packageStyle rectangle
skinparam classAttributeIconSize 0
skinparam classBackgroundColor #F7F7F7
skinparam packageBackgroundColor #FFFFFF
skinparam packageBorderColor #000000
skinparam classBorderColor #777777
skinparam classFontSize 22
skinparam packageFontSize 26

package "businessRules" {
  package "Entity" {
    class User {
      email: string
      roles: array
      password: string
      firstname: string
      lastname: string
    }

    class Post {
      title: string
      description: string
      createdAt: DateTimeInterface
    }

    class Picture {
      name: string
      url: string
    }

    User *-- Post : One\nTo\nMany
    Post *-- Picture : One\nTo\nMany
  }
}
@enduml
